class DeepLinkHandler(private val context: Context) {
    private val uriPattern = Pattern.compile("myapp://([a-zA-Z0-9_]+)/([a-zA-Z0-9_]+)")

    fun handleDeepLink(uri: Uri): Boolean {
        val matcher = uriPattern.matcher(uri)
        if (matcher.matches()) {
            val route = matcher.group(1)
            val parameter = matcher.group(2)
            when (route) {
                "profile" -> navigateToProfileActivity(parameter)
                "payment" -> navigateToPaymentConfirmationActivity()
            }
        }
    }

    private fun navigateToProfileActivity(userId: String) {
        val intent = Intent(context, ProfileActivity::class.java).apply {
            putExtra("user_id", userId)
        }
        context.startActivity(intent)
    }

    private fun navigateToPaymentConfirmationActivity() {
        val intent = Intent(context, PaymentConfirmationActivity::class.java)
        context.startActivity(intent)
    }
}